// ---------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------
func buildQueryString(filter models.TransportFilter) string {
	params := []string{}
	if filter.Model.Set && filter.Model.Value != "" {
		params = append(params, "model="+filter.Model.Value)
	}
	if filter.LicensePlate.Set && filter.LicensePlate.Value != "" {
		params = append(params, "license_plate="+filter.LicensePlate.Value)
	}
	if filter.PayloadCapacityMin.Set {
		params = append(params, "payload_min="+strconv.Itoa(int(filter.PayloadCapacityMin.Value)))
	}
	if filter.PayloadCapacityMax.Set {
		params = append(params, "payload_max="+strconv.Itoa(int(filter.PayloadCapacityMax.Value)))
	}
	if filter.FuelConsumptionMin.Set {
		params = append(params, "fuel_min="+strconv.Itoa(int(filter.FuelConsumptionMin.Value)))
	}
	if filter.FuelConsumptionMax.Set {
		params = append(params, "fuel_max="+strconv.Itoa(int(filter.FuelConsumptionMax.Value)))
	}
	if filter.SortBy.Set {
		params = append(params, "sort="+filter.SortBy.Value)
	}
	if filter.SortOrder.Set {
		params = append(params, "order="+filter.SortOrder.Value)
	}
	return strings.Join(params, "&")
}

func buildTransportsURL(baseQuery string, page int) string {
	if baseQuery == "" {
		return fmt.Sprintf("/transports?page=%d", page)
	}
	return fmt.Sprintf("/transports?%s&page=%d", baseQuery, page)
}

